templates.content:
{@io.quarkiverse.roq.frontmatter.runtime.model.NormalPage page}

{#if page.paginator}
  <nav class="pagination" role="navigation">
    <ul>
      {#if page.paginator.previous}
      <p><a class="newer-posts" href="{page.paginator.previous}">{#insert newer}‹{/insert}</a></p>
      {/if}

      {#if page.paginator.total > 1}
      <p><span class="page-number">{fm:pageNumber(page.paginator.currentIndex, page.paginator.total)}</span></p>
      {/if}

      {#if page.paginator.next}
      <p><a class="older-posts" href="{page.paginator.next}">{#insert older}›{/insert}</a></p>
      {/if}
    </ul>
  </nav>
{/if}

{@java.lang.String collectionName}
{@io.quarkiverse.roq.frontmatter.runtime.model.Site site}
{@io.quarkiverse.roq.frontmatter.runtime.model.NormalPage page}
{#let name=(collectionName ?: 'posts')}
<rss xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:content="http://purl.org/rss/1.0/modules/content/" xmlns:atom="http://www.w3.org/2005/Atom" version="2.0">
  <channel>
    <title><![CDATA[ {site.title} ]]></title>
    <description><![CDATA[ {site.description} ]]></description>
    <link>{site.url.absolute}</link>
    <atom:link href="{site.url('rss.xml').absolute}" rel="self" type="application/rss+xml"/>
    <generator>Quarkus Roq</generator>
    {#if site.collections.get(name)}
    <lastBuildDate>{#if site.collections.get(name).size > 0}{site.collections.get(name).get(0).date.format('EEE, dd MMM yyyy HH:mm:ss Z')}{/if}</lastBuildDate>
    {#for post in site.collections.get(name)}
      <item>
        <title><![CDATA[{post.title}]]></title>
        <link>{post.url.absolute}</link>
        <guid isPermaLink="false">{post.url.absolute}</guid>
        <pubDate>{post.date.format('EEE, dd MMM yyyy HH:mm:ss Z')}</pubDate>
        <description><![CDATA[{post.description}]]></description>
        <content:encoded><![CDATA[<p>{post.description}</p><div style="margin-top: 50px; font-style: italic;"><strong><a href="{post.url.absolute}">Keep reading</a>.</strong></div><br /> <br />]]></content:encoded>
      </item>
    {/for}
    {/if}
  </channel>
</rss>

{@java.lang.String pageTitle}
{@java.lang.String siteTitle}

{#if pageTitle || siteTitle}
  <!-- SEO TITLE -->
  {#capture title}{#if pageTitle && pageTitle ne siteTitle}{pageTitle} - {siteTitle}{#else}{siteTitle}{/if}{/capture}
  <title>{#include $title /}</title>
  <meta property="og:title" content="{pageTitle ?: siteTitle}" />
  <meta name="twitter:title" content="{pageTitle ?: siteTitle}">
{/if}
{#if siteTitle}
  <meta property="og:site_name" content="{siteTitle}">
{/if}

{#if pageLocale || siteLocale}
  <!-- SEO LOCALE -->
  <meta property="og:locale" content="{pageLocale ?: siteLocale}" />
{#else}
  <!-- SEO LOCALE -->
  <meta property="og:locale" content="{defaultLocale}" />
{/if}

{#if pageAuthor || siteAuthor}
  <!-- SEO AUTHOR -->
  <meta property="article:author" content="{pageAuthor ?: siteAuthor}" />
  <meta name="author" content="{pageAuthor ?: siteAuthor}" />
{/if}

{@io.quarkiverse.roq.frontmatter.runtime.model.Site site}
{@io.quarkiverse.roq.frontmatter.runtime.model.Page page}

{#if page.image}
  <!-- SEO IMAGE -->
  <meta name="twitter:card" content="summary_large_image" />
  <meta name="twitter:image:src" content="{page.image.absolute}" />
  <meta property="og:image" content="{page.image.absolute}" />
{#else}
  <!-- SEO IMAGE -->
  <meta name="twitter:card" content="summary">
{/if}

{@java.lang.String tag}
{#if tag}
    <script async src="https://www.googletagmanager.com/gtag/js?id=G-{tag}"></script>
    <script>
        window.dataLayer = window.dataLayer || [];
        function gtag()\{dataLayer.push(arguments);\}
        gtag('js', new Date());

        gtag('config', 'G-{tag}');
    </script>
{/if}

{@io.quarkiverse.roq.frontmatter.runtime.model.Page page}

{#if page.date}
  <!-- SEO TYPE -->
  <meta property="og:type" content="article" />
  <meta property="article:published_time" content="{page.date}" />
{#else}
  <!-- SEO TYPE -->
  <meta property="og:type" content="website" />
{/if}

{#if twitter}
  <!-- SEO TWITTER -->
  <meta name="twitter:site" content="@{twitter}" />
  <meta name="twitter:creator" content="@{twitter}" />
{/if}

{@io.quarkiverse.roq.frontmatter.runtime.model.DocumentPage page}
{#if page.collection??}
  <!-- SEO COLLECTION PAGES -->
  {#if page.prevPage}
  <link rel="prev" href="{page.prevPage.url.absolute}" />
  {/if}
  {#if page.nextPage}
  <link rel="next" href="{page.nextPage.url.absolute}" />
  {/if}
{/if}

{#if url}
  <!-- SEO URL -->
  <link rel="canonical" href="{url.absolute}" />
  <meta property="og:url" content="{url.absolute}" />
  <meta name="twitter:url" content="{url.absolute}">
{/if}

{@io.quarkiverse.roq.frontmatter.runtime.model.Site site}
{@io.quarkiverse.roq.frontmatter.runtime.model.Page page}

{#seoTitle pageTitle=page.title siteTitle=site.title /}
{#seoDescription pageDescription=page.description siteDescription=site.description /}
{#seoAuthor pageAuthor=page.data.author?? siteAuthor=site.data.author?? /}
{#seoUrl url=page.url /}
{#seoType page /}
{#seoImage page site /}
{#seoVerifications webmasterVerifications=site.data.webmasterVerifications?? /}
{#seoPaginator page site /}
{#seoFacebook facebook=site.data.facebook?? /}
{#seoTwitter twitter=site.data.twitter?? /}
{#seoLocale pageLocale=page.data.lang?? siteLocale=site.data.lang?? defaultLocale=global:locale /}
{#seoGenerator name="Quarkus Roq" version=global:roqVersion /}

{#if name}
  <!-- SEO GENERATOR -->
  <meta name="generator" content="{name} v{version}" />
{/if}

{#if webmasterVerifications}
  <!-- SEO VERIFICATION -->
  {#if webmasterVerifications.google}
    <meta name="google-site-verification" content="{webmasterVerifications.google}">
  {/if}
  {#if webmasterVerifications.bing}
    <meta name="msvalidate.01" content="{webmasterVerifications.bing}">
  {/if}
  {#if webmasterVerifications.alexa}
    <meta name="alexaVerifyID" content="{webmasterVerifications.alexa}">
  {/if}
  {#if webmasterVerifications.yandex}
    <meta name="yandex-verification" content="{webmasterVerifications.yandex}">
  {/if}
  {#if webmasterVerifications.baidu}
    <meta name="baidu-site-verification" content="{webmasterVerifications.baidu}">
  {/if}
  {#if webmasterVerifications.facebook}
    <meta name="facebook-domain-verification" content="{webmasterVerifications.facebook}">
  {/if}
{/if}

{@io.quarkiverse.roq.frontmatter.runtime.model.NormalPage page}
{#if page.paginator??}
  <!-- SEO PAGINATOR -->
  {#if page.paginator.previous}
  <link rel="prev" href="{page.paginator.previous.absolute}"/>
  {/if}
  {#if page.paginator.next}
  <link rel="next" href="{page.paginator.next.absolute}"/>
  {/if}
{/if}

{#if facebook}
  <!-- SEO FACEBOOK -->
  {#if facebook.admins}
    <meta property="fb:admins" content="{facebook.admins}" />
  {/if}

  {#if facebook.publisher}
    <meta property="article:publisher" content="{facebook.publisher}" />
  {/if}

  {#if facebook.app_id}
    <meta property="fb:app_id" content="{facebook.app_id}" />
  {/if}
{/if}

{#if pageDescription || siteDescription}
  <!-- SEO DESCRIPTION -->
  <meta name="description" content="{pageDescription ?: siteDescription}">
  <meta property="og:description" content="{pageDescription ?: siteDescription}" />
  <meta name="twitter:description" content="{pageDescription ?: siteDescription}">
{/if}

{@io.quarkiverse.roq.frontmatter.runtime.model.Site site}

{#if site.page("rss.xml")}
<link rel="alternate" type="application/rss+xml" title="{site.title}" href="{site.url('rss.xml').absolute}"/>
{/if}

{#let key?="app" tag?="both"}
{#if tag is "script" or tag is "both"}
  {#let src=inject:bundle.script(key)}
  {#if src}
    <script type="module" src="{src}"></script>
  {#else}
    <!-- no script found for key '{key}' in Bundler mapping !-->
  {/if}
{/if}
{#if key != "chunk"}
  {#if tag is "style" or tag is "both"}
    {#let href=inject:bundle.style(key)}
    {#if href}
      <link rel="stylesheet" href="{href}" />
    {#else}
      <!-- no style found for key '{key}' in Bundler mapping !-->
    {/if}
  {/if}
{/if}

---
layout: roq-default/main
---


{@io.quarkiverse.roq.frontmatter.runtime.model.NormalPage page}

<div class="hero">
  {#insert /}
</div>

{#if site.collections.get('posts')}
{#for post in site.collections.get('posts').paginated(page.paginator)}
<article class="post">
  {#if post.image}
  <a class="post-thumbnail" style='background-image: url("{post.image}")' href="{post.url}"></a>
  {/if}
  <div class="post-content">
    <h2 class="post-title"><a href="{post.url}">{post.title}</a></h2>
    <p>{post.description ?: post.contentAbstract}</p>
    <span class="post-date">{post.date.format('yyyy, MMM dd')}&nbsp;&nbsp;&nbsp;—&nbsp;</span>
    <span class="post-words">
      {post.readTime} minute(s) read
    </span>
  </div>
</article>
{/for}

{#include partials/roq-default/pagination.html/}
{/if}

---
layout: roq-default/default
---

{@io.quarkiverse.roq.frontmatter.runtime.model.Site site}

<aside class="sidebar main">
  {#insert header}
  <header>
    {#insert about}{#include partials/roq-default/sidebar-about /}{/}
    {#insert menu}{#include partials/roq-default/sidebar-menu menu=cdi:menu.items /}{/}
  </header> <!-- End Header -->
  {/}
  {#insert footer}
  <footer>
    {#insert contact}{#include partials/roq-default/sidebar-contact /}{/}
    {#insert copyright}{#include partials/roq-default/sidebar-copyright /}{/}
  </footer> <!-- End Footer -->
  {/}
</aside> <!-- End Sidebar -->
<div class="content-box clearfix">
  {#insert /}
</div>

---
layout: roq-default/main
---

{#insert before-page/}

{@io.quarkiverse.roq.frontmatter.runtime.model.DocumentPage page}
<div class="page-content">
  {#insert /}
</div>

{#insert after-page/}

{@io.quarkiverse.roq.frontmatter.runtime.model.Site site}
{@java.util.List<io.vertx.core.json.JsonObject> menu}
{@java.lang.String menuTitle}

<section class="menu">
  <h3 class="menu-title">{menuTitle ?: 'MENU'}</h3>
  <ul>
    {#for item in menu}
    <li><a href="{site.url(item.path)}" {#if item.target??}target="{item.target}"{/if}><i class="{item.icon}"></i>{item.title}</a> </li>
    {/for}
  </ul>
</section>

{@java.lang.String tag}

<meta charset="utf-8">

{#seo page site /}
{#rss site /}
{#favicon site/}

<base href="{page.url.relative}">
<meta http-equiv="X-UA-Compatible" content="IE=edge">
<meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1">


{#let color=site.data.getString('theme-color').or("#263959")}
<meta name="theme-color" content="{color}">
<meta name="msapplication-navbutton-color" content="{color}">
<meta name="apple-mobile-web-app-status-bar-style" content="{color}">
<link rel="stylesheet" href="{site.url.fromRoot('/static/bundle/roq.css')}?id={config:["roq-default.uuid"]}">

{#bundle /}

{#if site.data.containsKey("analytics")}
{#ga4 tag=site.data.getJsonObject('analytics').getString("ga4", "") /}
{/if}

{@io.quarkiverse.roq.frontmatter.runtime.model.DocumentPage page}

<div class="main">
    <h1>{roq_theme:notfound_title}</h1>
    {#if page.image}
    <img class="page-image" src="{page.image}" alt="{page.title}">
    {/}
    <p><b>Roq</b>: {roq_theme:notfound_text} <a href="{site.url}">{roq_theme:notfound_link}</a>.</p>
</div>

{@io.quarkiverse.roq.frontmatter.runtime.model.NormalPage page}
<?xml version="1.0" encoding="UTF-8"?>
{#if site.fileExists('sitemap.xsl')}
<?xml-stylesheet type="text/xsl" href="{site.file("sitemap.xsl").absolute}"?>
{/if}
<urlset xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xsi:schemaLocation="http://www.sitemaps.org/schemas/sitemap/0.9 http://www.sitemaps.org/schemas/sitemap/0.9/sitemap.xsd" xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">

    {#for collection in site.collections.list}
    {#if !collection.hidden && !collection.derived}
    {#for doc in collection}
    {#if doc.sitemap}
    <url>
        <loc>{doc.url.absolute}</loc>
        <lastmod>{doc.lastModifiedAt.iso}</lastmod>
    </url>
    {/if}
    {/for}
    {/if}
    {/for}
    {#for page in site.pages}
    {#if page.source.isTargetHtml && page.sitemap}
    <url>
        <loc>{page.url.absolute}</loc>
        <lastmod>{page.lastModifiedAt.iso}</lastmod>
    </url>
    {/if}
    {/for}
</urlset>

{@io.quarkiverse.roq.frontmatter.runtime.model.Page page}

{#if cdi:series}
{#let series=cdi:series.get(page)}
{#if series}
<section class="series">
  <h3>{series:header(series.title, series.documents.size)}</h3>
  <ul>
    {#for doc in series.documents}
    <li>
      {#if doc.id == page.id}
      <span class="index">{doc_count}</span>
      <span class="title">{doc.title}</span>
      {#else}
      <a href="{doc.url}">
        <span class="index">{doc_count}</span>
        <span class="title">{doc.title}</span>
      </a>
      {/if}
    </li>
    {/for}
  </ul>
</section>
{/if}
{/let}
{/if}
